#include <bits/stdc++.h>
using namespace std;

int n, q;
int f1[100005][25];
int f2[100005][25];
vector<int> son[100005];

void dfs(int x, int fa) {
    for (int i = 1; i <= 20; i++) {
        f1[x][i] = f1[f1[x][i - 1]][i - 1];
    }
    f2[x][0] = INT_MAX;
    for (int i : son[x]) {
        dfs(i, x);
        f2[x][0] = min(f2[x][0], i);
    }
    if (f2[x][0] == INT_MAX) {
        for (int i = 0; i <= 20; i++) {
            f2[x][i] = x;
        }
        return ;
    }
    for (int i = 1; i <= 20; i++) {
        f2[x][i] = f2[f2[x][i - 1]][i - 1];
    }
}

int main() {
    memset(f1, -1, sizeof(f1));
    memset(f2, -1, sizeof(f2));
    cin >> n >> q;
    f1[1][0] = 1;
    for (int i = 2; i <= n; i++) {
        int p;
        cin >> p;
        f1[i][0] = p;
        son[p].push_back(i);
    }
    dfs(1, 1);
    while (q--) {
        int s, k, a;
        cin >> s >> k;
        for (int i = 0; i < k; i++) {
            cin >> a;
            if (a > 0) {
                for (int j = 20; j >= 0; j--) {
                    if (a >= (1 << j)) {
                        s = f1[s][j];
                        a -= 1 << j;
                    }
                }
            }
            else {
                a = -a;
                for (int j = 20; j >= 0; j--) {
                    if (a >= (1 << j)) {
                        s = f2[s][j];
                        a -= 1 << j;
                    }
                }
            }
        }
        cout << s << endl;
    }
    return 0;
}
